import os
import re
import json
import datetime
import openpyxl
import argparse
from tqdm import tqdm
from concurrent.futures import ProcessPoolExecutor, as_completed
from functools import partial


PROJECT_ROOT = os.path.abspath(os.path.join(os.path.dirname(__file__), os.pardir))
DATA_ROOT = os.path.join(PROJECT_ROOT, "data")


def datetime_to_float(dt):
    excel_start_date = datetime.datetime(1899, 12, 30)
    delta = dt - excel_start_date
    return delta.days + delta.seconds / 86400.0


def transform_value(v):
    if isinstance(v, (int, float)):
        v = round(float(v), 2)
    elif isinstance(v, datetime.time):
        v = str(v)[:-3]
    elif isinstance(v, datetime.datetime):
        v = round(datetime_to_float(v), 0)
    elif isinstance(v, str):
        try:
            v = round(float(v), 2)
        except ValueError:
            pass
    return v


def compare_cell_value(v1, v2, tolerance=0.01):

    # Handle ArrayFormula objects — compare by formula text
    if hasattr(v1, 'text') and hasattr(v2, 'text'):
        return v1.text == v2.text

    # Treat #DIV/0! and #N/A as equivalent to finance "not meaningful" placeholders.
    # E.g. golden=#DIV/0! and AI="N/A" (via IFERROR) should match.
    _DISPLAY_EQUIVALENT_ERRORS = {'#DIV/0!', '#N/A'}
    _NOT_MEANINGFUL = _DISPLAY_EQUIVALENT_ERRORS | {
        'N/A', 'NA', 'N.A.', 'N/M', 'NM', 'N.M.',
        'NOT MEANINGFUL', 'NOT APPLICABLE', 'NOT AVAILABLE',
        '\u2014', '\u2013', '-', '--', '---',
    }
    def _is_not_meaningful(v):
        if v is None:
            return False
        if isinstance(v, str):
            s = v.strip().upper()
            return s in _NOT_MEANINGFUL or s in _DISPLAY_EQUIVALENT_ERRORS
        return False

    if _is_not_meaningful(v1) and _is_not_meaningful(v2):
        return True

    # For two numeric values, compare on raw values with tolerance only —
    # skip rounding to avoid boundary artifacts (e.g. -0.105 vs -0.10500000000000001)
    if isinstance(v1, (int, float)) and isinstance(v2, (int, float)):
        if v1 == v2:
            return True
        if v1 == 0 or v2 == 0:
            return abs(v1 - v2) <= tolerance
        return abs(v1 - v2) / max(abs(v1), abs(v2)) <= tolerance

    # transform_value rounds and normalizes types — needed for string-encoded
    # numbers, datetimes, etc. but numeric-vs-numeric is already handled above.
    v1 = transform_value(v1)
    v2 = transform_value(v2)
    if (v1 == "" and v2 is None) or (v1 is None and v2 == ""):
        return True
    if (v1 == "" and v2 == "") or (v1 is None and v2 is None):
        return True
    # Treat None as equivalent to 0 (rounding can produce 0 from near-zero values,
    # and empty cells read as None)
    if (v1 is None and isinstance(v2, (int, float)) and v2 == 0) or \
       (v2 is None and isinstance(v1, (int, float)) and v1 == 0):
        return True
    if type(v1) != type(v2):
        # print(type(v1), type(v2))
        return False
    if v1 == v2:
        return True
    # Formula strings: compare case-insensitively (Excel function names are case-insensitive)
    if isinstance(v1, str) and isinstance(v2, str) and v1.startswith('=') and v2.startswith('='):
        return v1.replace('$', '').upper() == v2.replace('$', '').upper()
    # Numeric type: check 1% tolerance
    if isinstance(v1, (int, float)) and isinstance(v2, (int, float)):
        if v1 == 0 and v2 == 0:
            return True
        if v1 == 0 or v2 == 0:
            # Use absolute error when one value is 0
            return abs(v1 - v2) <= tolerance
        # Use relative error
        relative_error = abs(v1 - v2) / max(abs(v1), abs(v2))
        return relative_error <= tolerance
    return False


def _get_color_rgb(color) -> str:
    """Extract RGB value from color object, resolving theme colors to RGB."""
    if not color:
        return "00000000"
    # Check color.type to determine how the color is stored
    # openpyxl descriptors return validator objects when the attribute isn't set,
    # so we must check color.type rather than testing color.theme/color.rgb directly
    if color.type == "rgb" and isinstance(color.rgb, str):
        return color.rgb
    if color.type == "theme":
        # Standard Excel theme color map (Office default theme)
        _THEME_COLORS = [
            "FFFFFF",  # 0: lt1 (white/light background)
            "000000",  # 1: dk1 (black/dark text)
            "E7E6E6",  # 2: lt2 (light gray)
            "44546A",  # 3: dk2 (dark blue-gray)
            "4472C4",  # 4: accent1
            "ED7D31",  # 5: accent2
            "A5A5A5",  # 6: accent3
            "FFC000",  # 7: accent4
            "5B9BD5",  # 8: accent5
            "70AD47",  # 9: accent6
        ]
        theme_idx = color.theme
        if 0 <= theme_idx < len(_THEME_COLORS):
            base = _THEME_COLORS[theme_idx]
            tint = float(color.tint) if color.tint else 0.0
            if tint != 0:
                r, g, b = int(base[0:2], 16), int(base[2:4], 16), int(base[4:6], 16)
                if tint > 0:
                    r = int(r + (255 - r) * tint)
                    g = int(g + (255 - g) * tint)
                    b = int(b + (255 - b) * tint)
                else:
                    r = int(r * (1 + tint))
                    g = int(g * (1 + tint))
                    b = int(b * (1 + tint))
                r, g, b = min(255, max(0, r)), min(255, max(0, g)), min(255, max(0, b))
                base = f"{r:02X}{g:02X}{b:02X}"
            return "FF" + base
    return "00000000"


def _compare_colors(color1, color2) -> bool:
    """Compare two colors using only last 6 characters (RGB), ignoring alpha channel."""
    rgb1 = _get_color_rgb(color1)
    rgb2 = _get_color_rgb(color2)
    return rgb1[-6:] == rgb2[-6:]


def compare_font_color(font_gt, font_proc) -> bool:
    """Compare font colors between two cells."""
    return _compare_colors(font_gt.color, font_proc.color)


def compare_cell_formula(cell1, cell2) -> bool:
    """Compare formulas of two cells (workbook must be loaded with data_only=False)."""
    f1, f2 = cell1.value, cell2.value

    # Handle ArrayFormula objects (CSE array formulas) — compare by formula text
    if hasattr(f1, 'text') and hasattr(f2, 'text'):
        return f1.text == f2.text

    # Both are formulas: compare formula strings (ignoring $ absolute ref markers, case,
    # and legacy =+ prefix which is equivalent to =)
    if isinstance(f1, str) and isinstance(f2, str) and f1.startswith('=') and f2.startswith('='):
        def _normalize_formula(f):
            f = f.replace('$', '').upper()
            if f.startswith('=+'):
                f = '=' + f[2:]
            return f
        return _normalize_formula(f1) == _normalize_formula(f2)

    # Treat None and "" as equivalent empty
    empty = (None, "")
    if f1 in empty and f2 in empty:
        return True

    # For non-formula values (e.g. floats), use tolerance-based comparison
    return compare_cell_value(f1, f2)


def parse_answer_position(answer_position):
    """Parse answer_position string, handling sheet names with commas (e.g., "'ACC,Dil'!B2:K52")."""
    result, current, in_quote = [], "", False
    for char in answer_position:
        if char == "'":
            in_quote = not in_quote
        if char == ',' and not in_quote:
            if current.strip():
                result.append(current.strip())
            current = ""
        else:
            current += char
    if current.strip():
        result.append(current.strip())
    return result


def col_num2name(n):
    """ Convert a column number to an Excel column name """
    name = ''
    while n > 0:
        n, remainder = divmod(n - 1, 26)
        name = chr(65 + remainder) + name
    return name


def col_name2num(name):
    """ Convert an Excel column name to a column number """
    num = 0
    for c in name:
        num = num * 26 + (ord(c) - ord('A') + 1)
    return num


def parse_cell_range(range_str):
    """ Parse a range string like 'A1:AB12' """
    start_cell, end_cell = range_str.split(':')
    start_col, start_row = '', ''
    for char in start_cell:
        if char.isdigit():
            start_row += char
        else:
            start_col += char
    
    end_col, end_row = '', ''
    for char in end_cell:
        if char.isdigit():
            end_row += char
        else:
            end_col += char

    return (col_name2num(start_col), int(start_row)), (col_name2num(end_col), int(end_row))


def generate_cell_names(range_str):
    """ Generate a list of all cell names in the specified range """
    if ':' not in range_str:
        return [range_str]
    (start_col, start_row), (end_col, end_row) = parse_cell_range(range_str)
    columns = [col_num2name(i) for i in range(start_col, end_col + 1)]
    cell_names = [f"{col}{row}" for col in columns for row in range(start_row, end_row + 1)]
    return cell_names


_EXCEL_ERRORS = {'#REF!', '#VALUE!', '#DIV/0!', '#NAME?', '#NULL!', '#N/A', '#NUM!'}


def _find_sheet(wb, name):
    """Find a worksheet by name with whitespace-tolerant, case-insensitive matching."""
    if name in wb.sheetnames:
        return wb[name]
    name_stripped = name.strip().lower()
    for sn in wb.sheetnames:
        if sn.strip().lower() == name_stripped:
            return wb[sn]
    return None


def _has_excel_error(cell):
    """Check if a cell value is an Excel error string."""
    v = cell.value
    return isinstance(v, str) and v in _EXCEL_ERRORS


def _compare_cells(cell1, cell2, with_font_color, with_formula):
    """Helper function to compare two cells."""
    if with_formula:
        return compare_cell_formula(cell1, cell2)
    elif with_font_color:
        return compare_cell_value(cell1.value, cell2.value) and compare_font_color(cell1.font, cell2.font)
    else:
        return compare_cell_value(cell1.value, cell2.value)


def classify_cells_by_modification(wb_input, wb_answer, sheet_name, cell_range, with_font_color=False, with_formula=False,
                                    wb_input_formula=None, wb_answer_formula=None):
    """Classify cells into regression (unmodified) and modification (modified) categories."""
    ws_input = _find_sheet(wb_input, sheet_name)
    ws_answer = _find_sheet(wb_answer, sheet_name)
    if ws_input is None or ws_answer is None:
        return [], []

    # Formula-level worksheets for error value fallback
    ws_input_f = _find_sheet(wb_input_formula, sheet_name) if wb_input_formula else None
    ws_answer_f = _find_sheet(wb_answer_formula, sheet_name) if wb_answer_formula else None
    regression, modification = [], []

    for cell_name in generate_cell_names(cell_range):
        cell_in, cell_ans = ws_input[cell_name], ws_answer[cell_name]
        # If either cell has an Excel error value and we have formula workbooks, compare formulas instead
        if not with_formula and ws_input_f and ws_answer_f and (_has_excel_error(cell_in) or _has_excel_error(cell_ans)):
            is_same = compare_cell_formula(ws_input_f[cell_name], ws_answer_f[cell_name])
        else:
            is_same = _compare_cells(cell_in, cell_ans, with_font_color, with_formula)
        (regression if is_same else modification).append(cell_name)

    return regression, modification


def cell_level_compare_with_classification(wb_answer, wb_output, sheet_name, regression_cells, modification_cells, with_font_color=False, with_formula=False,
                                           wb_answer_formula=None, wb_output_formula=None):
    """Compare output and answer, calculate accuracy for regression and modification separately."""
    if _find_sheet(wb_output, sheet_name) is None:
        return 0, len(regression_cells), 0, len(modification_cells), [f"{sheet_name} worksheet not found"]

    ws_answer = _find_sheet(wb_answer, sheet_name)
    ws_output = _find_sheet(wb_output, sheet_name)
    # Formula-level worksheets for error value fallback
    ws_answer_f = _find_sheet(wb_answer_formula, sheet_name) if wb_answer_formula else None
    ws_output_f = _find_sheet(wb_output_formula, sheet_name) if wb_output_formula else None

    def count_correct(cells, label):
        correct, errors = 0, []
        for name in cells:
            cell_ans, cell_out = ws_answer[name], ws_output[name]
            # If either cell has an Excel error value and we have formula workbooks, compare formulas
            if not with_formula and ws_answer_f and ws_output_f and (_has_excel_error(cell_ans) or _has_excel_error(cell_out)):
                matched = compare_cell_formula(ws_answer_f[name], ws_output_f[name])
            else:
                matched = _compare_cells(cell_ans, cell_out, with_font_color, with_formula)
            if matched:
                correct += 1
            else:
                ans_val = cell_ans.value
                out_val = cell_out.value
                # Extract text from ArrayFormula objects
                if hasattr(ans_val, 'text'):
                    ans_val = ans_val.text
                if hasattr(out_val, 'text'):
                    out_val = out_val.text
                errors.append(f"{label} error at {sheet_name}!{name}: answer={ans_val}, output={out_val}")
        return correct, errors

    reg_correct, reg_errors = count_correct(regression_cells, "Regression")
    mod_correct, mod_errors = count_correct(modification_cells, "Modification")

    return reg_correct, len(regression_cells), mod_correct, len(modification_cells), reg_errors + mod_errors


def compare_workbooks_with_regression(input_file, gt_file, proc_file, answer_position, with_font_color=False, with_formula=False):
    """
    Compare workbooks, distinguish between regression and modification scores.
    Returns: (is_correct, error_message, correct_cells, total_cells, regression_stats, modification_stats)
    """
    empty_stats = {'correct': 0, 'total': 0}
    
    if not os.path.exists(proc_file):
        return False, "output file not exist", 0, 0, empty_stats, empty_stats.copy()
    if not os.path.exists(input_file):
        return False, "input file not exist", 0, 0, empty_stats, empty_stats.copy()
    
    # Only with_formula mode needs raw formulas; with_font_color should use calculated values
    need_raw_data = with_formula
    try:
        wb_input = openpyxl.load_workbook(filename=input_file, data_only=not need_raw_data)
        wb_gt = openpyxl.load_workbook(filename=gt_file, data_only=not need_raw_data)
        wb_proc = openpyxl.load_workbook(filename=proc_file, data_only=not need_raw_data)
        # Load formula-level workbooks for error value fallback (only when not already in formula mode)
        if not with_formula:
            wb_input_formula = openpyxl.load_workbook(filename=input_file, data_only=False)
            wb_gt_formula = openpyxl.load_workbook(filename=gt_file, data_only=False)
            wb_proc_formula = openpyxl.load_workbook(filename=proc_file, data_only=False)
        else:
            wb_input_formula = wb_gt_formula = wb_proc_formula = None
    except Exception as e:
        return False, str(e), 0, 0, empty_stats, empty_stats.copy()

    reg_stats, mod_stats = {'correct': 0, 'total': 0}, {'correct': 0, 'total': 0}
    total_correct, total_cells, error_msgs = 0, 0, []
    
    for sheet_cell_range in parse_answer_position(answer_position):
        if '!' in sheet_cell_range:
            sheet_name, cell_range = sheet_cell_range.split('!')
        else:
            sheet_name, cell_range = wb_gt.sheetnames[0], sheet_cell_range
        sheet_name = sheet_name.strip("'").strip()
        cell_range = cell_range.strip("'").strip()

        regression_cells, modification_cells = classify_cells_by_modification(
            wb_input, wb_gt, sheet_name, cell_range, with_font_color, with_formula,
            wb_input_formula=wb_input_formula, wb_answer_formula=wb_gt_formula
        )
        reg_correct, reg_total, mod_correct, mod_total, msgs = cell_level_compare_with_classification(
            wb_gt, wb_proc, sheet_name, regression_cells, modification_cells, with_font_color, with_formula,
            wb_answer_formula=wb_gt_formula, wb_output_formula=wb_proc_formula
        )
        
        reg_stats['correct'] += reg_correct
        reg_stats['total'] += reg_total
        mod_stats['correct'] += mod_correct
        mod_stats['total'] += mod_total
        total_correct += reg_correct + mod_correct
        total_cells += reg_total + mod_total
        error_msgs.extend(msgs)

    is_correct = (total_correct == total_cells)
    first_error = next((m for m in error_msgs if m), "")
    return is_correct, first_error if not is_correct else "", total_correct, total_cells, reg_stats, mod_stats


def parse_option():
    parser = argparse.ArgumentParser("command line arguments for evaluation with regression/modification split.")

    parser.add_argument('--model', type=str, default='llama', help='model name')
    parser.add_argument('--dataset', type=str, default="Debugging", help='dataset name')
    parser.add_argument('--outputs-dir', type=str, default=None, help='outputs directory path (output files)')
    parser.add_argument('--workers', type=int, default=1, help='number of parallel workers (default: 1, single process)')

    opt = parser.parse_args()

    return opt


def process_single_item(data, dataset_path, outputs_base_dir, api_calls_map, dataset_name):
    """Process a single data item for parallel execution."""
    data_id = str(data['id'])
    input_file = os.path.join(dataset_path, data['spreadsheet_path'])
    gt_file = os.path.join(dataset_path, data['golden_response_path'])
    proc_file = os.path.join(outputs_base_dir, f"{data_id}_output.xlsx")
    
    # Determine comparison mode
    with_font_color = False
    with_formula = False
    if 'Debugging' in dataset_name:
        golden_path = data.get('spreadsheet_path', '')
        if 'Color' in golden_path:
            with_font_color = True
        if 'Embedded' in golden_path:
            with_formula = True    
    
    missing = False
    try:
        result, error_msg, _, _, regression_stats, modification_stats = compare_workbooks_with_regression(
            input_file, gt_file, proc_file, data['answer_position'],
            with_font_color=with_font_color, with_formula=with_formula
        )
        if not result and "not exist" in error_msg:
            missing = True
    except Exception as e:
        result = False
        error_msg = str(e)
        regression_stats = {'correct': 0, 'total': 0}
        modification_stats = {'correct': 0, 'total': 0}
    
    error_message = error_msg if not result else ""
    reg_ratio = round(regression_stats['correct'] / regression_stats['total'], 4) if regression_stats['total'] else 0.0
    mod_ratio = round(modification_stats['correct'] / modification_stats['total'], 4) if modification_stats['total'] else 0.0
    # If regression ratio >= 99.8%, treat as 1.0
    if reg_ratio >= 0.998:
        reg_ratio = 1.0
    accuracy = 1.0 if reg_ratio == 1.0 and mod_ratio == 1.0 else 0.0

    result_item = {
        'id': data['id'],
        'error_message': error_message,
        'regression_accuracy': reg_ratio,
        'modification_accuracy': mod_ratio,
        'accuracy': accuracy,
        'interaction_turns': api_calls_map.get(data_id, 0),
    }

    return result_item, missing


def evaluation(opt):
    dataset_path = os.path.join(DATA_ROOT, opt.dataset)
    with open(os.path.join(dataset_path, 'dataset.json'), 'r') as fp:
        dataset = json.load(fp)

    if not opt.outputs_dir:
        raise ValueError("--outputs-dir is required")
    outputs_base_dir = opt.outputs_dir

    # Derive trajectories directory from outputs directory
    trajectories_dir = opt.outputs_dir.replace('/output_excel/', '/spreadsheet/')

    # Read api_calls data from trajectories directory
    api_calls_map = {}
    if os.path.exists(trajectories_dir):
        for folder_name in os.listdir(trajectories_dir):
            folder_path = os.path.join(trajectories_dir, folder_name)
            if os.path.isdir(folder_path):
                traj_files = [f for f in os.listdir(folder_path) if f.endswith('.traj')]
                if traj_files:
                    traj_file_path = os.path.join(folder_path, traj_files[0])
                    try:
                        with open(traj_file_path, 'r', encoding='utf-8', errors='ignore') as f:
                            content = f.read()
                        match = re.search(r'"api_calls"\s*:\s*(\d+)', content)
                        if match:
                            api_calls_map[folder_name] = int(match.group(1))
                    except Exception:
                        pass

    eval_results = []
    missing_outputs = 0
    
    num_workers = opt.workers
    
    if num_workers <= 1:
        # Single process mode (original behavior)
        for data in tqdm(dataset, desc="Evaluating"):
            result_item, missing = process_single_item(
                data, dataset_path, outputs_base_dir, api_calls_map, opt.dataset
            )
            eval_results.append(result_item)
            if missing:
                missing_outputs += 1
    else:
        # Multi-process parallel mode
        process_func = partial(
            process_single_item,
            dataset_path=dataset_path,
            outputs_base_dir=outputs_base_dir,
            api_calls_map=api_calls_map,
            dataset_name=opt.dataset
        )
        
        with ProcessPoolExecutor(max_workers=num_workers) as executor:
            futures = {executor.submit(process_func, data): data['id'] for data in dataset}
            
            for future in tqdm(as_completed(futures), total=len(futures), desc=f"Evaluating (workers={num_workers})"):
                try:
                    result_item, missing = future.result()
                    eval_results.append(result_item)
                    if missing:
                        missing_outputs += 1
                except Exception as e:
                    data_id = futures[future]
                    eval_results.append({
                        'id': data_id,
                        'error_message': f"Worker error: {str(e)}",
                        'regression_accuracy': 0.0,
                        'modification_accuracy': 0.0,
                        'accuracy': 0.0,
                    })
        
        # Sort results by id to maintain consistent order
        eval_results.sort(key=lambda x: x['id'])
    
    # Calculate global statistics
    def avg(lst): return round(sum(lst) / len(lst), 4) if lst else 0.0
    
    reg_ratios = [r['regression_accuracy'] for r in eval_results if "not exist" not in r.get('error_message', '')]
    mod_ratios = [r['modification_accuracy'] for r in eval_results if "not exist" not in r.get('error_message', '')]
    acc_scores = [r['accuracy'] for r in eval_results]
    api_calls = [r['interaction_turns'] for r in eval_results]

    final_results = {
        'total_tests': len(eval_results),
        'missing_outputs': missing_outputs,
        'regression_accuracy': avg(reg_ratios),
        'modification_accuracy': avg(mod_ratios),
        'accuracy': avg(acc_scores),
        'interaction_turns_stats': {
            'average': round(sum(api_calls) / len(api_calls), 2),
            'maximum': max(api_calls),
            'minimum': min(api_calls),
        },
    }
    final_results['scores'] = eval_results
    
    # Extract timestamp from path
    timestamp_suffix = ""
    if path := (opt.outputs_dir or opt.trajectories_dir):
        if match := re.search(r'(\d{8}-\d{6})$', os.path.basename(path.rstrip('/'))):
            timestamp_suffix = f"_{match.group(1)}"
    
    os.makedirs(f'results/{opt.dataset}', exist_ok=True)
    with open(f'results/{opt.dataset}/{opt.model}_{opt.dataset}_{timestamp_suffix}_regression.json', 'w') as fp:
        json.dump(final_results, fp, indent=4, ensure_ascii=False)


if __name__ == "__main__":
    opt = parse_option()
    print(opt)

    evaluation(opt)
